// ─────────────────────────────────────
// LOKASI CARD (Diperbarui untuk merender gambar asli)
// ─────────────────────────────────────
function LokasiCard({ item, index, isFav, onToggleFav, onLihatPeta }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.05, duration: 0.3 }}
      style={{
        background: 'white', borderRadius: 20,
        border: '1px solid #ECECEC',
        boxShadow: '0 2px 16px rgba(0,0,0,0.04)',
        display: 'flex', alignItems: 'stretch', overflow: 'hidden',
        transition: 'box-shadow 0.2s',
        fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
      }}
      whileHover={{ boxShadow: '0 8px 24px rgba(0,0,0,0.08)' }}
    >
      {/* Container Gambar Asli */}
      <div style={{
        width: 180, flexShrink: 0,
        background: `linear-gradient(135deg, ${item.color}15, ${item.color}30)`,
        position: 'relative',
        overflow: 'hidden',
        borderRight: '1px solid #ECECEC'
      }}>
        {/* Gambar Lokasi */}
        <img
          src={item.image}
          alt={item.name}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            position: 'absolute',
            inset: 0,
            transition: 'transform 0.4s ease'
          }}
          onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.08)'}
          onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
          onError={(e) => {
            // Fallback kembali ke warna gradasi jika gambar gagal diload (internet lambat/terputus)
            e.target.style.display = 'none';
          }}
        />

        {/* Gradasi overlay atas hitam tipis agar badge kategori tetap terbaca jelas di atas gambar terang */}
        <div style={{
          position: 'absolute',
          inset: 0,
          background: 'linear-gradient(to bottom, rgba(0,0,0,0.4) 0%, transparent 40%)',
          pointerEvents: 'none'
        }} />

        {/* Category badge */}
        <div style={{
          position: 'absolute', top: 12, left: 12,
          background: item.color, color: 'white',
          fontSize: 10, fontWeight: 700, padding: '4px 10px', borderRadius: 20,
          boxShadow: '0 2px 8px rgba(0,0,0,0.2)',
          zIndex: 10
        }}>
          {item.categoryLabel}
        </div>
      </div>

      {/* Content */}
      <div style={{ flex: 1, padding: '20px 24px', display: 'flex', gap: 20 }}>

        {/* Info utama */}
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 8 }}>
            <div>
              <h3 style={{ fontSize: 16, fontWeight: 700, color: '#111827', margin: 0, marginBottom: 4 }}>
                {item.name}
              </h3>
              <div style={{ display: 'flex', alignItems: 'center', gap: 4 }}>
                <MapPin size={11} color="#9CA3AF" />
                <span style={{ fontSize: 11, color: '#9CA3AF', fontWeight: 400 }}>{item.address}</span>
              </div>
            </div>
            {/* Favorit button */}
            <button
              onClick={() => onToggleFav(item.id)}
              style={{ background: 'none', border: 'none', cursor: 'pointer', padding: '4px', borderRadius: 8, flexShrink: 0, marginLeft: 8 }}
            >
              <Heart
                size={18}
                color={isFav ? '#EF4444' : '#D1D5DB'}
                fill={isFav ? '#EF4444' : 'none'}
                style={{ transition: 'all 0.2s' }}
              />
            </button>
          </div>

          <p style={{ fontSize: 13, color: '#6B7280', lineHeight: 1.6, margin: '0 0 12px', display: '-webkit-box', WebkitLineClamp: 2, WebkitBoxOrient: 'vertical', overflow: 'hidden' }}>
            {item.description}
          </p>

          {/* Tombol Lihat di Peta */}
          <button
            onClick={() => onLihatPeta(item)}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 6,
              padding: '8px 16px', borderRadius: 12,
              border: `1.5px solid ${item.color}`,
              background: 'white', color: item.color,
              fontSize: 12, fontWeight: 600, cursor: 'pointer',
              transition: 'all 0.15s',
            }}
            onMouseEnter={e => { e.currentTarget.style.background = `${item.color}10` }}
            onMouseLeave={e => { e.currentTarget.style.background = 'white' }}
          >
            <Navigation2 size={13} /> Lihat di Peta
          </button>
        </div>

        {/* Info teknis kanan */}
        <div style={{ width: 170, flexShrink: 0, display: 'flex', flexDirection: 'column', gap: 12, justifyContent: 'center' }}>
          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
              <Tag size={12} color="#9CA3AF" />
              <span style={{ fontSize: 10, color: '#9CA3AF', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Kategori</span>
            </div>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#374151' }}>{item.categoryLabel}</div>
          </div>

          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
              <Clock size={12} color="#9CA3AF" />
              <span style={{ fontSize: 10, color: '#9CA3AF', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Jam Buka</span>
            </div>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#374151' }}>{item.jamBuka}</div>
          </div>

          <div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
              <Building size={12} color="#9CA3AF" />
              <span style={{ fontSize: 10, color: '#9CA3AF', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.5px' }}>Dibangun</span>
            </div>
            <div style={{ fontSize: 13, fontWeight: 600, color: '#374151' }}>{item.dibangun}</div>
          </div>
        </div>
      </div>
    </motion.div>
  )
}

