// INFORMASI LOKASI PAGE
// ─────────────────────────────────────
export default function InformasiLokasi() {
  const navigate = useNavigate()
  const [search, setSearch] = useState('')
  const [category, setCategory] = useState('semua')
  const [page, setPage] = useState(1)
  const [favorites, setFavorites] = useState(new Set())
  const [filterOpen, setFilterOpen] = useState(false)

  // Filter
  const filtered = LOKASI_DATA.filter(item => {
    const matchSearch = !search.trim() ||
      item.name.toLowerCase().includes(search.toLowerCase()) ||
      item.description.toLowerCase().includes(search.toLowerCase()) ||
      item.address.toLowerCase().includes(search.toLowerCase())
    const matchCat = category === 'semua' || item.category === category
    return matchSearch && matchCat
  })

  const totalPages = Math.max(1, Math.ceil(filtered.length / ITEMS_PER_PAGE))
  const currentItems = filtered.slice((page - 1) * ITEMS_PER_PAGE, page * ITEMS_PER_PAGE)

  const handleToggleFav = (id) => {
    setFavorites(prev => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  const handleLihatPeta = (item) => {
    navigate('/cari-rute')
  }

  const handleCategoryChange = (key) => {
    setCategory(key)
    setPage(1)
    setFilterOpen(false)
  }

  const activeCat = CATEGORIES.find(c => c.key === category)

  return (
    <div style={{ display: 'flex', height: '100vh', width: '100vw', background: '#F6F7FB', overflow: 'hidden', fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif' }}>
      <SharedSidebar />

      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>

        {/* Header */}
        <div style={{ padding: '32px 36px 20px', flexShrink: 0 }}>
          <motion.div initial={{ opacity: 0, y: -8 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.4 }}>
            <h1 style={{ fontSize: 28, fontWeight: 800, color: '#111827', margin: 0, letterSpacing: '-0.3px' }}>Informasi Lokasi</h1>
            <p style={{ fontSize: 14, color: '#6B7280', margin: '6px 0 0', fontWeight: 500 }}>
              Temukan informasi lengkap tentang tempat-tempat ikonik di Jakarta
            </p>
          </motion.div>
        </div>

        {/* Toolbar: Search + Filter */}
        <div style={{ padding: '0 36px 16px', display: 'flex', alignItems: 'center', gap: 12, flexShrink: 0 }}>

          {/* Search bar */}
          <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: 10, background: 'white', border: '1px solid #ECECEC', borderRadius: 16, padding: '12px 18px', boxShadow: '0 1px 6px rgba(0,0,0,0.03)' }}>
            <Search size={16} color="#9CA3AF" />
            <input
              value={search}
              onChange={e => { setSearch(e.target.value); setPage(1) }}
              placeholder="Cari lokasi, kategori, atau alamat..."
              style={{ flex: 1, border: 'none', outline: 'none', fontSize: 14, color: '#374151', background: 'transparent', fontFamily: 'inherit' }}
            />
            {search && (
              <button onClick={() => { setSearch(''); setPage(1) }} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#9CA3AF', fontSize: 16, lineHeight: 1, padding: 0 }}>×</button>
            )}
          </div>

          {/* Filter kategori dropdown */}
          <div style={{ position: 'relative' }}>
            <button
              onClick={() => setFilterOpen(p => !p)}
              style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '12px 18px', background: 'white', border: '1px solid #ECECEC',
                borderRadius: 16, fontSize: 13, fontWeight: 500, cursor: 'pointer',
                color: category === 'semua' ? '#6B7280' : activeCat?.color || '#6B7280',
                boxShadow: '0 1px 6px rgba(0,0,0,0.03)',
                transition: 'all 0.15s',
              }}
            >
              <Filter size={14} />
              {activeCat?.label || 'Semua Kategori'}
              <ChevronDown size={14} style={{ transition: 'transform 0.2s', transform: filterOpen ? 'rotate(180deg)' : 'rotate(0)' }} />
            </button>

            {filterOpen && (
              <motion.div
                initial={{ opacity: 0, y: -4, scale: 0.97 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                exit={{ opacity: 0 }}
                style={{
                  position: 'absolute', top: 'calc(100% + 8px)', right: 0, zIndex: 100,
                  background: 'white', borderRadius: 16, border: '1px solid #ECECEC',
                  boxShadow: '0 8px 24px rgba(0,0,0,0.1)', overflow: 'hidden',
                  minWidth: 200,
                }}
              >
                {CATEGORIES.map(cat => (
                  <button
                    key={cat.key}
                    onClick={() => handleCategoryChange(cat.key)}
                    style={{
                      width: '100%', display: 'flex', alignItems: 'center', gap: 10,
                      padding: '10px 16px', border: 'none', background: category === cat.key ? '#F5F5FF' : 'none',
                      cursor: 'pointer', fontSize: 13, fontWeight: category === cat.key ? 600 : 400,
                      color: category === cat.key ? cat.color : '#374151', textAlign: 'left',
                      transition: 'background 0.1s',
                    }}
                    onMouseEnter={e => { if (category !== cat.key) e.currentTarget.style.background = '#F9FAFB' }}
                    onMouseLeave={e => { if (category !== cat.key) e.currentTarget.style.background = 'none' }}
                  >
                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: cat.color, flexShrink: 0 }} />
                    {cat.label}
                    {category === cat.key && <span style={{ marginLeft: 'auto', color: cat.color }}>✓</span>}
                  </button>
                ))}
              </motion.div>
            )}
          </div>

          {/* Result count */}
          <div style={{ fontSize: 13, color: '#9CA3AF', whiteSpace: 'nowrap', fontWeight: 500 }}>
            {filtered.length} lokasi
          </div>
        </div>

        {/* Scrollable content */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '0 36px 24px' }} onClick={() => filterOpen && setFilterOpen(false)}>

          {currentItems.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '60px 0' }}>
              <div style={{ fontSize: 40, marginBottom: 12 }}>🔍</div>
              <div style={{ fontSize: 15, fontWeight: 600, color: '#374151', marginBottom: 4 }}>Tidak ditemukan</div>
              <div style={{ fontSize: 13, color: '#9CA3AF' }}>Coba kata kunci atau kategori lain</div>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
              {currentItems.map((item, i) => (
                <LokasiCard
                  key={item.id}
                  item={item}
                  index={i}
                  isFav={favorites.has(item.id)}
                  onToggleFav={handleToggleFav}
                  onLihatPeta={handleLihatPeta}
                />
              ))}
            </div>
          )}
        </div>

        {/* Pagination */}
        {filtered.length > ITEMS_PER_PAGE && (
          <div style={{ padding: '12px 36px 24px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, flexShrink: 0 }}>
            <button
              onClick={() => setPage(p => Math.max(1, p - 1))}
              disabled={page === 1}
              style={{ width: 36, height: 36, borderRadius: 10, border: '1px solid #ECECEC', background: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: page === 1 ? 'not-allowed' : 'pointer', opacity: page === 1 ? 0.4 : 1, color: '#374151' }}
            >
              <ChevronLeft size={16} />
            </button>

            {Array.from({ length: totalPages }, (_, i) => i + 1)
              .filter(p => p === 1 || p === totalPages || Math.abs(p - page) <= 1)
              .reduce((acc, p, i, arr) => {
                if (i > 0 && p - arr[i - 1] > 1) acc.push('...')
                acc.push(p)
                return acc
              }, [])
              .map((p, i) => p === '...' ? (
                <span key={`dot-${i}`} style={{ width: 36, textAlign: 'center', color: '#9CA3AF', fontSize: 13 }}>…</span>
              ) : (
                <button key={p} onClick={() => setPage(p)}
                  style={{ width: 36, height: 36, borderRadius: 10, border: page === p ? 'none' : '1px solid #ECECEC', background: page === p ? '#5B5FEF' : 'white', color: page === p ? 'white' : '#374151', fontSize: 13, fontWeight: page === p ? 700 : 500, cursor: 'pointer', transition: 'all 0.15s' }}>
                  {p}
                </button>
              ))
            }

            <button
              onClick={() => setPage(p => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
              style={{ width: 36, height: 36, borderRadius: 10, border: '1px solid #ECECEC', background: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: page === totalPages ? 'not-allowed' : 'pointer', opacity: page === totalPages ? 0.4 : 1, color: '#374151' }}
            >
              <ChevronRight size={16} />
            </button>
          </div>
        )}
      </div>
    </div>
  )
}